use std::collections::HashMap;
use serde::{Deserialize, Serialize};

#[derive(Debug, Deserialize, Serialize)]
struct TokenRequest {
    tokens: Vec<String>,
}

#[derive(Debug, Deserialize, Serialize)]
struct GatewayResponse {
    valid_count: usize,
    processed_tokens: HashMap<String, bool>,
}

fn validate_tokens(request_body: TokenRequest) -> GatewayResponse {
    let mut processed_tokens = HashMap::new();
    let mut valid_count = 0;

    for token in request_body.tokens {
        // Simulate an external validation call for demonstration purposes
        let is_valid = !token.starts_with("expired:");
        processed_tokens.insert(token, is_valid);
        if is_valid {
            valid_count += 1;
        }
    }

    GatewayResponse {
        valid_count,
        processed_tokens,
    }
}

