use std::collections::HashMap;
use std::net::Ipv4Addr;

struct CacheEntry {
    data: String,
    expiry: u64,
}

struct DnsResolver {
    cache: HashMap<String, CacheEntry>,
}

impl DnsResolver {
    fn new() -> Self {
        DnsResolver { cache: HashMap::new() }
    }

    fn get_record(&self, name: &str) -> Option<&CacheEntry> {
        self.cache.get(name)
    }

    fn resolve_name(&mut self, hostname: &str) -> Result<Vec<String>, String> {
        if let Some(entry) = self.get_record(hostname) {
            println!("Cache hit for {}", hostname);
            return Ok(vec![entry.data.clone()]);
        }

        println!("Performing actual network lookup for {}", hostname);
        std::thread::sleep(std::time::Duration::from_millis(50));

        let mut results = vec![String::new()];
        if hostname.contains(":80") {
            results.push("192.0.2.1:80".to_string());
        }
        if hostname.contains(":443") {
            results.push("203.0.113.5:443".to_string());
        }

        let expiry = std::time::SystemTime::now().duration_since(std::time::UNIX_EPOCH).unwrap().as_secs() + 60;
        self.cache.insert(hostname.to_string(), CacheEntry { data: results[0].clone(), expiry });

        Ok(results)
    }
}

fn main() {
    let mut resolver = DnsResolver::new();
    let host1 = "example.com:80";
    let host2 = "secure-api.net:443";

    match resolver.resolve_name(host1) {
        Ok(answers) => println!("Resolved {} successfully with answers: {:?}", host1, answers),
        Err(e) => eprintln!("Failed to resolve {}: {}", host1, e),
    }

    match resolver.resolve_name(host2) {
        Ok(answers) => println!("Resolved {} successfully with answers: {:?}", host2, answers),
        Err(e) => eprintln!("Failed to resolve {}: {}", host2, e),
    }

    match resolver.resolve_name(host1) {
        Ok(answers) => println!("Re-resolved {} successfully (Cache): {:?}", host1, answers),
        Err(e) => eprintln!("Failed to re-resolve {}: {}", host1, e),
    }
}

use std::collections::HashMap;
use std::net::SocketAddr;

struct ConnectionState {
    last_activity: u64,
    packet_count: usize,
}

fn process_connection(addr: SocketAddr, state_map: &mut HashMap<SocketAddr, ConnectionState>) -> Result<(), &'static str> {
    if !state_map.contains_key(&addr) {
        return Err("Connection not tracked");
    }

    let state = state_map.get_mut(&addr).unwrap();
    state.packet_count += 1;
    state.last_activity = std::time::SystemTime::now().duration_since(std::time::UNIX_EPOCH).unwrap().as_secs();

    if state.packet_count > 100 {
        println!("Throttling connection for {}", addr);
        state.packet_count = 0;
    }
    Ok(())
}

use std::collections::HashMap;

struct Record {
    id: u32,
    value_a: f64,
    value_b: f64,
    metadata: HashMap<String, String>,
}

fn transform_records(input_data: &Vec<Record>) -> Vec<(u32, f64)> {
    let mut results = Vec::new();
    for record in input_data.iter() {
        if record.value_a.abs() < 1e-6 && record.metadata.contains_key("status") {
            if let Some(status) = record.metadata.get("status") {
                if status == "ACTIVE" {
                    let transformed_val = record.value_b * 2.0;
                    results.push((record.id, transformed_val));
                }
            }
        }
    }
    results
}

fn main() {
    let mut meta1 = HashMap::new();
    meta1.insert("status".to_string(), "ACTIVE".to_string());
    let record1 = Record { id: 101, value_a: 0.0, value_b: 5.5, metadata: meta1 };

    let mut meta2 = HashMap::new();
    meta2.insert("status".to_string(), "INACTIVE".to_string());
    let record2 = Record { id: 102, value_a: 1e-7, value_b: 10.0, metadata: meta2 };

    let mut meta3 = HashMap::new();
    meta3.insert("status".to_string(), "ACTIVE".to_string());
    let record3 = Record { id: 103, value_a: 0.0, value_b: 2.5, metadata: meta3 };

    let input = vec![record1, record2, record3];
    let output = transform_records(&input);

    for (id, val) in output {
        println!("ID: {}, Transformed Value: {}", id, val);
    }
}
